  2	import * as React from 'react';
  3	import { IncidentsHeader } from './IncidentsHeader/IncidentsHeader';
  4	import { useSafeFetch } from '../console/utils/safe-fetch-hook';
  5	import { createAlertsQuery, fetchDataForIncidentsAndAlerts } from './api';
  6	import { useTranslation } from 'react-i18next';
  7	import {
  8	  Bullseye,
  9	  Button,
 10	  Select,
 11	  SelectList,
 12	  SelectOption,
 13	  Spinner,
 14	  Toolbar,
 15	  ToolbarContent,
 16	  ToolbarFilter,
 17	  ToolbarItem,
 18	  MenuToggle,
 19	  Badge,
 20	  Title,
 21	  PageSection,
 22	  PageSectionVariants,
 23	} from '@patternfly/react-core';
 24	import { Helmet } from 'react-helmet';
 25	import { IncidentsTable } from './IncidentsTable';
 26	import {
 27	  getIncidentsTimeRanges,
 28	  processIncidents,
 29	  processIncidentsForAlerts,
 30	} from './processIncidents';
 31	import {
 32	  filterIncident,
 33	  onDeleteGroupIncidentFilterChip,
 34	  onDeleteIncidentFilterChip,
 35	  onIncidentFiltersSelect,
 36	  parseUrlParams,
 37	  updateBrowserUrl,
 38	  usePatternFlyTheme,
 39	} from './utils';
 40	import { groupAlertsForTable, processAlerts } from './processAlerts';
 41	import { CompressArrowsAltIcon, CompressIcon, FilterIcon } from '@patternfly/react-icons';
 42	import { useDispatch, useSelector } from 'react-redux';
 43	import {
 44	  setAlertsAreLoading,
 45	  setAlertsData,
 46	  setAlertsTableData,
 47	  setFilteredIncidentsData,
 48	  setIncidents,
 49	  setIncidentsActiveFilters,
 50	} from '../../actions/observe';
 51	import { useLocation } from 'react-router-dom';
 52	import { usePerspective } from '../hooks/usePerspective';
 53	import { changeDaysFilter } from './utils';
 54	import { parsePrometheusDuration } from '../console/console-shared/src/datetime/prometheus';
 55	import withFallback from '../console/console-shared/error/fallbacks/withFallback';
 56	
 57	const IncidentsPage = () => {
 58	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 59	  const dispatch = useDispatch();
 60	  const location = useLocation();
 61	  const urlParams = parseUrlParams(location.search);
 62	  const { perspective } = usePerspective();
 63	  const { theme } = usePatternFlyTheme();
 64	  // loading states
 65	  const [incidentsAreLoading, setIncidentsAreLoading] = React.useState(true);
 66	  // days span is where we store the value for creating time ranges for
 67	  // fetch incidents/alerts based on the length of time ranges
 68	  // when days filter changes we set a new days span -> calculate new time range and fetch new data
 69	  const [daysSpan, setDaysSpan] = React.useState();
 70	  const [timeRanges, setTimeRanges] = React.useState([]);
 71	  // data that is used for processing to serve it to the alerts table and chart
 72	  const [incidentForAlertProcessing, setIncidentForAlertProcessing] = React.useState([]);
 73	  const [hideCharts, setHideCharts] = React.useState(false);
 74	
 75	  const [incidentFilterIsExpanded, setIncidentIsExpanded] = React.useState(false);
 76	  const [daysFilterIsExpanded, setDaysFilterIsExpanded] = React.useState(false);
 77	
 78	  const onIncidentFilterToggle = (ev) => {
 79	    ev.stopPropagation();
 80	    setIncidentIsExpanded(!incidentFilterIsExpanded);
 81	  };
 82	  const onToggleClick = (ev) => {
 83	    ev.stopPropagation();
 84	    setDaysFilterIsExpanded(!daysFilterIsExpanded);
 85	  };
 86	
 87	  const incidentsInitialState = useSelector((state) =>
 88	    state.plugins.mcp.getIn(['incidentsData', 'incidentsInitialState']),
 89	  );
 90	
 91	  const incidents = useSelector((state) => state.plugins.mcp.getIn(['incidentsData', 'incidents']));
 92	
 93	  const incidentsActiveFilters = useSelector((state) =>
 94	    state.plugins.mcp.getIn(['incidentsData', 'incidentsActiveFilters']),
 95	  );
 96	
 97	  const incidentGroupId = useSelector((state) =>
 98	    state.plugins.mcp.getIn(['incidentsData', 'incidentGroupId']),
 99	  );
100	
101	  const alertsData = useSelector((state) =>
102	    state.plugins.mcp.getIn(['incidentsData', 'alertsData']),
103	  );
104	
105	  const alertsAreLoading = useSelector((state) =>
106	    state.plugins.mcp.getIn(['incidentsData', 'alertsAreLoading']),
107	  );
108	
109	  const filteredData = useSelector((state) =>
110	    state.plugins.mcp.getIn(['incidentsData', 'filteredIncidentsData']),
111	  );
112	  React.useEffect(() => {
113	    const hasUrlParams = Object.keys(urlParams).length > 0;
114	
115	    if (hasUrlParams) {
116	      // If URL parameters exist, update incidentsActiveFilters based on them
117	      dispatch(
118	        setIncidentsActiveFilters({
119	          incidentsActiveFilters: {
120	            ...incidentsInitialState,
121	            ...urlParams,
122	          },
123	        }),
124	      );
125	    } else {
126	      // If no URL parameters exist, set the URL based on incidentsInitialState
127	      updateBrowserUrl(incidentsInitialState);
128	      dispatch(
129	        setIncidentsActiveFilters({
130	          incidentsActiveFilters: {
131	            ...incidentsInitialState,
132	          },
133	        }),
134	      );
135	    }
136	  }, []);
137	
138	  React.useEffect(() => {
139	    updateBrowserUrl(incidentsActiveFilters);
140	  }, [incidentsActiveFilters]);
141	
142	  React.useEffect(() => {
143	    dispatch(
144	      setFilteredIncidentsData({
145	        filteredIncidentsData: filterIncident(incidentsActiveFilters, incidents),
146	      }),
147	    );
148	  }, [incidentsActiveFilters.incidentFilters]);
149	
150	  const now = Date.now();
151	  const safeFetch = useSafeFetch();
152	  const title = t('Incidents');
153	
154	  React.useEffect(() => {
155	    setTimeRanges(getIncidentsTimeRanges(daysSpan, now));
156	  }, [daysSpan]);
157	
158	  React.useEffect(() => {
159	    setDaysSpan(
160	      parsePrometheusDuration(
161	        incidentsActiveFilters.days.length > 0
162	          ? incidentsActiveFilters.days[0].split(' ')[0] + 'd'
163	          : '',
164	      ),
165	    );
166	  }, [incidentsActiveFilters.days]);
167	
168	  React.useEffect(() => {
169	    (async () => {
170	      Promise.all(
171	        timeRanges.map(async (range) => {
172	          const response = await fetchDataForIncidentsAndAlerts(
173	            safeFetch,
174	            range,
175	            createAlertsQuery(incidentForAlertProcessing),
176	            perspective,
177	          );
178	          return response.data.result;
179	        }),
180	      )
181	        .then((results) => {
182	          const aggregatedData = results.reduce((acc, result) => acc.concat(result), []);
183	          dispatch(
184	            setAlertsData({
185	              alertsData: processAlerts(aggregatedData, incidentForAlertProcessing),
186	            }),
187	          );
188	          dispatch(setAlertsAreLoading({ alertsAreLoading: false }));
189	        })
190	        .catch((err) => {
191	          // eslint-disable-next-line no-console
192	          console.log(err);
193	        });
194	    })();
195	  }, [incidentForAlertProcessing]);
196	
197	  React.useEffect(() => {
198	    dispatch(
199	      setAlertsTableData({
200	        alertsTableData: groupAlertsForTable(alertsData),
201	      }),
202	    );
203	  }, [alertsAreLoading]);
204	
205	  React.useEffect(() => {
206	    (async () => {
207	      Promise.all(
208	        timeRanges.map(async (range) => {
209	          const response = await fetchDataForIncidentsAndAlerts(
210	            safeFetch,
211	            range,
212	            'cluster:health:components:map',
213	            perspective,
214	          );
215	          return response.data.result;
216	        }),
217	      )
218	        .then((results) => {
219	          const aggregatedData = results.reduce((acc, result) => acc.concat(result), []);
220	          dispatch(
221	            setIncidents({
222	              incidents: processIncidents(aggregatedData),
223	            }),
224	          );
225	          dispatch(
226	            setFilteredIncidentsData({
227	              filteredIncidentsData: filterIncident(
228	                urlParams ? incidentsActiveFilters : incidentsInitialState,
229	                processIncidents(aggregatedData),
230	              ),
231	            }),
232	          );
233	          setIncidentsAreLoading(false);
234	        })
235	        .catch((err) => {
236	          // eslint-disable-next-line no-console
237	          console.log(err);
238	        });
239	    })();
240	  }, [timeRanges]);
241	
242	  React.useEffect(() => {
243	    if (incidentGroupId) {
244	      Promise.all(
245	        timeRanges.map(async (range) => {
246	          const response = await fetchDataForIncidentsAndAlerts(
247	            safeFetch,
248	            range,
249	            `cluster:health:components:map{group_id='${incidentGroupId}'}`,
250	            perspective,
251	          );
252	          return response.data.result;
253	        }),
254	      )
255	        .then((results) => {
256	          const aggregatedData = results.reduce((acc, result) => acc.concat(result), []);
257	          setIncidentForAlertProcessing(processIncidentsForAlerts(aggregatedData));
258	          dispatch(setAlertsAreLoading({ alertsAreLoading: true }));
259	          setIncidentsAreLoading(false);
260	        })
261	        .catch((err) => {
262	          // eslint-disable-next-line no-console
263	          console.log(err);
264	        });
265	    }
266	  }, [incidentGroupId, timeRanges]);
267	
268	  const onSelect = (_event, value) => {
269	    if (value) {
270	      changeDaysFilter(value, dispatch, incidentsActiveFilters);
271	    }
272	
273	    setDaysFilterIsExpanded(false);
274	  };
275	
276	  return (
277	    <>
278	      <Helmet>
279	        <title>{title}</title>
280	      </Helmet>
281	      <PageSection variant={PageSectionVariants.light}>
282	        <Title headingLevel="h1">{t('Incidents')}</Title>
283	      </PageSection>
284	      {alertsAreLoading && incidentsAreLoading ? (
285	        <Bullseye>
286	          <Spinner aria-label="incidents-chart-spinner" />
287	        </Bullseye>
288	      ) : (
289	        <PageSection variant={PageSectionVariants.light}>
290	          <Toolbar
291	            id="toolbar-with-filter"
292	            className="pf-v5-m-toggle-group-container"
293	            collapseListedFiltersBreakpoint="xl"
294	            clearAllFilters={() =>
295	              onDeleteIncidentFilterChip('', '', incidentsActiveFilters, dispatch)
296	            }
297	          >
298	            <ToolbarContent>
299	              <ToolbarItem>
300	                <ToolbarFilter
301	                  labels={incidentsActiveFilters.incidentFilters}
302	                  deleteLabel={(category, chip) =>
303	                    onDeleteIncidentFilterChip(category, chip, incidentsActiveFilters, dispatch)
304	                  }
305	                  deleteLabelGroup={(category) =>
306	                    onDeleteGroupIncidentFilterChip(category, incidentsActiveFilters, dispatch)
307	                  }
308	                  categoryName="Filters"
309	                >
310	                  <Select
311	                    id="severity-select"
312	                    role="menu"
313	                    aria-label="Filters"
314	                    isOpen={incidentFilterIsExpanded}
315	                    selected={incidentsActiveFilters.incidentFilters}
316	                    onSelect={(event, selection) =>
317	                      onIncidentFiltersSelect(event, selection, dispatch, incidentsActiveFilters)
318	                    }
319	                    onOpenChange={(isOpen) => setIncidentIsExpanded(isOpen)}
320	                    toggle={(toggleRef) => (
321	                      <MenuToggle
322	                        ref={toggleRef}
323	                        onClick={onIncidentFilterToggle}
324	                        isExpanded={incidentFilterIsExpanded}
325	                        icon={<FilterIcon />}
326	                        badge={
327	                          Object.entries(incidentsActiveFilters.incidentFilters).length > 0 ? (
328	                            <Badge isRead>
329	                              {Object.entries(incidentsActiveFilters.incidentFilters).length}
330	                            </Badge>
331	                          ) : undefined
332	                        }
333	                      >
334	                        Filters
335	                      </MenuToggle>
336	                    )}
337	                    shouldFocusToggleOnSelect
338	                  >
339	                    <SelectList>
340	                      <SelectOption
341	                        value="Critical"
342	                        isSelected={incidentsActiveFilters.incidentFilters.includes('Critical')}
343	                        description="The incident is critical."
344	                        hasCheckbox
345	                      >
346	                        Critical
347	                      </SelectOption>
348	                      <SelectOption
349	                        value="Warning"
350	                        isSelected={incidentsActiveFilters.incidentFilters.includes('Warning')}
351	                        description="The incident might lead to critical."
352	                        hasCheckbox
353	                      >
354	                        Warning
355	                      </SelectOption>
356	                      <SelectOption
357	                        value="Informative"
358	                        isSelected={incidentsActiveFilters.incidentFilters.includes('Informative')}
359	                        description="The incident is not critical."
360	                        hasCheckbox
361	                      >
362	                        Informative
363	                      </SelectOption>
364	                      <SelectOption
365	                        value="Firing"
366	                        isSelected={incidentsActiveFilters.incidentFilters.includes('Firing')}
367	                        description="The incident is currently firing."
368	                        hasCheckbox
369	                      >
370	                        Firing
371	                      </SelectOption>
372	                      <SelectOption
373	                        value="Resolved"
374	                        isSelected={incidentsActiveFilters.incidentFilters.includes('Resolved')}
375	                        description="The incident is not currently firing."
376	                        hasCheckbox
377	                      >
378	                        Resolved
379	                      </SelectOption>
380	                    </SelectList>
381	                  </Select>
382	                </ToolbarFilter>
383	              </ToolbarItem>
384	              <ToolbarItem>
385	                <Select
386	                  id="time-range-select"
387	                  isOpen={daysFilterIsExpanded}
388	                  selected={incidentsActiveFilters.days[0]}
389	                  onSelect={onSelect}
390	                  onOpenChange={(isOpen) => setDaysFilterIsExpanded(isOpen)}
391	                  toggle={(toggleRef) => (
392	                    <MenuToggle
393	                      ref={toggleRef}
394	                      onClick={onToggleClick}
395	                      isExpanded={daysFilterIsExpanded}
396	                    >
397	                      {incidentsActiveFilters.days[0]}
398	                    </MenuToggle>
399	                  )}
400	                  shouldFocusToggleOnSelect
401	                >
402	                  <SelectList>
403	                    <SelectOption value="1 day">{t('1 day')}</SelectOption>
404	                    <SelectOption value="3 days">{t('3 days')}</SelectOption>
405	                    <SelectOption value="7 days">{t('7 days')}</SelectOption>
406	                    <SelectOption value="15 days">{t('15 days')}</SelectOption>
407	                  </SelectList>
408	                </Select>
409	              </ToolbarItem>
410	              <ToolbarItem align={{ default: 'alignRight' }}>
411	                <Button
412	                  variant="link"
413	                  icon={hideCharts ? <CompressArrowsAltIcon /> : <CompressIcon />}
414	                  onClick={() => setHideCharts(!hideCharts)}
415	                >
416	                  <span>{hideCharts ? t('Show graph') : t('Hide graph')}</span>
417	                </Button>
418	              </ToolbarItem>
419	            </ToolbarContent>
420	          </Toolbar>
421	          {hideCharts ? (
422	            ''
423	          ) : (
424	            <IncidentsHeader
425	              alertsData={alertsData}
426	              incidentsData={filteredData}
427	              chartDays={timeRanges.length}
428	              theme={theme}
429	            />
430	          )}
431	          <IncidentsTable />
432	        </PageSection>
433	      )}
434	    </>
435	  );
436	};
437	
438	const incidentsPageWithFallback = withFallback(IncidentsPage);
439	
440	export default incidentsPageWithFallback;

