 73	
 74	  const [incidentFilterIsExpanded, setIncidentIsExpanded] = React.useState(false);
 75	  const [daysFilterIsExpanded, setDaysFilterIsExpanded] = React.useState(false);
 76	
 77	  const onIncidentFilterToggle = (ev) => {
 78	    ev.stopPropagation();
 79	    setIncidentIsExpanded(!incidentFilterIsExpanded);
 80	  };
