373	                        isSelected={incidentsActiveFilters.incidentFilters.includes('Resolved')}
374	                        description="The incident is not currently firing."
375	                        hasCheckbox
376	                      >
377	                        Resolved
378	                      </SelectOption>
379	                    </SelectList>
380	                  </Select>
381	                </ToolbarFilter>
382	              </ToolbarItem>
383	              <ToolbarItem>
384	                <Select
385	                  id="time-range-select"
386	                  isOpen={daysFilterIsExpanded}
387	                  selected={incidentsActiveFilters.days[0]}
388	                  onSelect={onSelect}
389	                  onOpenChange={(isOpen) => setDaysFilterIsExpanded(isOpen)}
390	                  toggle={(toggleRef) => (
