412	                  icon={hideCharts ? <CompressArrowsAltIcon /> : <CompressIcon />}
413	                  onClick={() => setHideCharts(!hideCharts)}
414	                >
415	                  <span>{hideCharts ? t('Show graph') : t('Hide graph')}</span>
416	                </Button>
417	              </ToolbarItem>
418	            </ToolbarContent>
419	          </Toolbar>
420	          {hideCharts ? (
421	            ''
422	          ) : (
423	            <IncidentsHeader
