425	              incidentsData={filteredData}
426	              chartDays={timeRanges.length}
427	              theme={theme}
428	            />
429	          )}
430	          <IncidentsTable />
431	        </PageSection>
432	      )}
433	    </>
434	  );
435	};
436	
437	const incidentsPageWithFallback = withFallback(IncidentsPage);
438	
439	export default incidentsPageWithFallback;

